51	const CURSED_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	
55	const computeItemSurcharges = (
56	  items: { type: string; cursed?: boolean; enchantment?: number }[],
57	): number =>
58	  items.reduce((total, item) => {
59	    if (!isMainItem(item.type)) {
60	      return total;
61	    }
62	    const base = MAIN_ITEM_BASE_PREMIUMS[item.type];
63	    let surcharge = 0;
64	    if (item.cursed) {
65	      surcharge += base * CURSED_SURCHARGE_RATE;
66	    }
67	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
68	      surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
69	    }
70	    return total + surcharge;
71	  }, 0);
72	
73	const LOYALTY_DISCOUNT_RATE = 0.2;
74	const LOYALTY_THRESHOLD_YEARS = 2;
75	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
76	
77	type PremiumContext = {
78	  items: { type: string; cursed?: boolean; enchantment?: number }[];
79	  isLoyalCustomer: boolean;
80	  isFollowUpContract: boolean;
81	};
82	
83	const computeStepPremium = (context: PremiumContext): number => {
84	  const basePremium = computeBasePremium(context.items);
85	  const itemSurcharges = computeItemSurcharges(context.items);
86	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
87	  const loyaltyDiscount = context.isLoyalCustomer
88	    ? basePremium * LOYALTY_DISCOUNT_RATE
89	    : 0;
90	  const followUpDiscount = context.isFollowUpContract
91	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
92	    : 0;
93	  return (
94	    basePremium +
95	    itemSurcharges +
96	    firstInsuranceSurcharge -
97	    loyaltyDiscount -
98	    followUpDiscount +
99	    PROCESSING_FEE
100	  );
101	};
102	
103	const INSURANCE_VALUES: Record<string, number> = {
104	  sword: 1000,
105	  amulet: 600,
106	  staff: 800,
107	  potion: 400,
108	  rune: 250,
109	  moonstone: 250,
110	};
111	
112	const DEDUCTIBLE_PER_DAMAGE = 100;
113	const CAP_MULTIPLIER = 2;
114	
115	type PolicyItem = { type: string; enchantment?: number };
116	
117	type PolicyState = {
118	  items: PolicyItem[];
119	  remainingCap: number;
120	};
121	
122	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
124	
125	const computeInsuranceSum = (items: { type: string }[]): number =>
126	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
127	
128	const findPolicyItemOrThrow = (
129	  items: PolicyItem[],
130	  itemType: string,
131	): PolicyItem => {
132	  const item = items.find((i) => i.type === itemType);
133	  if (!item) {
134	    throw new Error(`Damaged item type not in policy: ${itemType}`);
135	  }
136	  return item;
137	};
138	
139	const computeDamagePayout = (
140	  damage: { itemType: string; amount: number },
141	  items: PolicyItem[],
142	): number => {
143	  const item = findPolicyItemOrThrow(items, damage.itemType);
144	  const reimbursable =
145	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
146	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
147	      : damage.amount;
148	  return reimbursable - DEDUCTIBLE_PER_DAMAGE;
149	};
150	
151	const computeClaimPayout = (
152	  damages: { itemType: string; amount: number }[],
153	  items: PolicyItem[],
154	): number =>
155	  damages.reduce((total, damage) => total + computeDamagePayout(damage, items), 0);
156	
157	type QuoteContext = {
158	  items: { type: string; cursed?: boolean; enchantment?: number }[];
159	  isLoyalCustomer: boolean;
160	  isFollowUpContract: boolean;
161	};
162	
163	const handleQuote = (
164	  step: any,
165	  index: number,
166	  policies: Record<number, PolicyState>,
167	  isLoyalCustomer: boolean,
168	): { premium: number } => {
169	  const items = step?.items ?? [];
170	  for (const item of items) {
171	    if (!isKnownItemType(item.type)) {
172	      throw new Error(`Unknown item type: ${item.type}`);
173	    }
174	  }
175	  policies[index] = {
176	    items,
177	    remainingCap: computeInsuranceSum(items) * CAP_MULTIPLIER,
178	  };
179	  const context: QuoteContext = {
180	    items,
181	    isLoyalCustomer,
182	    isFollowUpContract: index > 0,
183	  };
184	  return { premium: Math.ceil(computeStepPremium(context)) };
185	};
186	
187	const handleClaim = (
188	  step: any,
189	  policies: Record<number, PolicyState>,
190	): { payout: number; remainingCap: number } => {
191	  const policy = policies[step.policy];
192	  const damages = step?.incident?.damages ?? [];
193	  const desiredPayout = computeClaimPayout(damages, policy.items);
194	  const payout = Math.floor(Math.min(desiredPayout, policy.remainingCap));
195	  policy.remainingCap -= payout;
196	  return { payout, remainingCap: policy.remainingCap };
197	};
198	
199	export const runScenario = (scenario: any): unknown => {
200	  const steps = scenario?.steps ?? [];
201	  const isLoyalCustomer =
202	    (scenario?.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
203	  const policies: Record<number, PolicyState> = {};
204	  const results = steps.map((step: any, index: number) =>
205	    step?.op === "claim"
206	      ? handleClaim(step, policies)
207	      : handleQuote(step, index, policies, isLoyalCustomer),
208	  );
209	  return { results };
210	};
